import React, { useEffect, useRef, useState } from 'react';
import { Link, useParams } from 'react-router-dom';
import './style.css';

function PostDetails() {
  const { id } = useParams();
  const [post, setPost] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const notesRef = useRef(null);

  const handleFocusNotes = () => {
    if (notesRef.current) {
      notesRef.current.focus();
    }
  };

  useEffect(() => {
    setIsLoading(true);

    fetch(`https://jsonplaceholder.typicode.com/posts/${id}`)
      .then((response) => {
        if (!response.ok) {
          throw new Error('Post not found');
        }

        return response.json();
      })
      .then((data) => {
        setPost(data);
        setIsLoading(false);
      })
      .catch(() => {
        setPost(null);
        setIsLoading(false);
      });
  }, [id]);

  if (isLoading) {
    return (
      <main className="post-details-page">
        <section className="post-details-card">
          <p className="post-details-tag">Post Details</p>
          <h1>Loading post...</h1>
          <p className="post-details-text">Please wait while we load the article.</p>
        </section>
      </main>
    );
  }

  if (!post) {
    return (
      <main className="post-details-page">
        <section className="post-details-card">
          <p className="post-details-tag">Post Details</p>
          <h1>Post not found</h1>
          <p className="post-details-text">The requested post does not exist.</p>
          <Link to="/posts" className="post-details-link">Back to Posts</Link>
        </section>
      </main>
    );
  }

  return (
    <main className="post-details-page">
      <article className="post-details-card">
        <div className="post-details-meta">
          <p className="post-details-tag">User {post.userId}</p>
          <span className="post-details-id">Post #{post.id}</span>
        </div>
        <h1>{post.title}</h1>
        <p className="post-details-text">
          A focused article view with live data from the API and a cleaner editorial presentation.
        </p>
        <p className="post-details-body">{post.body}</p>
        <section className="post-details-notes">
          <div className="post-details-notes-header">
            <h2>Ref Example</h2>
            <button type="button" className="post-details-focus-button" onClick={handleFocusNotes}>
              Focus Notes
            </button>
          </div>
          <p className="post-details-notes-text">
            This button uses <code>useRef</code> to move the cursor directly into the textarea.
          </p>
          <textarea
            ref={notesRef}
            className="post-details-textarea"
            placeholder="Write a quick note about this post..."
            rows="4"
          />
        </section>
        <Link to="/posts" className="post-details-link">Back to Posts</Link>
      </article>

    </main>
  );
}

export default PostDetails;
